#include <bits/stdc++.h>
using namespace std;

const int N=110;

int n,k,w[N],d[N],dis[N],sz[N];
long long f[N][N][55],g[N][55];
vector<int> e[N];
bool isf[N];

void dfs(int x){
    for(int i=1;i<=n;i++)
        if(isf[i])
            f[x][i][0]=1ll*w[x]*(dis[x]-dis[i]);
    f[x][x][1]=0;
    isf[x]=1;
    sz[x]=1;
    for(int y:e[x]){
        dis[y]=dis[x]+d[y];
        dfs(y);
        memset(g,0x3f,sizeof(g));
        for(int i=0;i<=sz[x];i++)
            for(int j=0;j<=sz[y] && i+j<=k;j++)
                for(int p=1;p<=n;p++){
                    if(!isf[p])
                        continue;
                    g[p][i+j]=min(g[p][i+j],f[x][p][i]+min(f[y][p][j],f[y][y][j]));
                }
        sz[x]+=sz[y];
        for(int i=1;i<=n;i++)
            for(int j=0;j<=sz[x];j++)
                f[x][i][j]=g[i][j];
    }
    isf[x]=0;
}

int main(){
    scanf("%d%d",&n,&k);
    n++,k++;
    for(int i=2,v;i<=n;i++){
        scanf("%d%d%d",&w[i],&v,&d[i]);
        e[v+1].push_back(i);
    }
    memset(f,0x3f,sizeof(f));
    dfs(1);
    printf("%lld",f[1][1][k]);
    return 0;
}
